onChangeEvent.script:
// Get the newly selected value
var selectedPosition = form.currentFieldValue;

//console.log('Position changed to:', selectedPosition);

if (selectedPosition === 'positionOther') {
    // Show the text field and enable it
    form.showField('custom.positionOther');
    form.enableField('custom.positionOther');
} else {
    // Hide the text field and clear any value
    form.hideField('custom.positionOther');
    form.setValue('custom.positionOther', '');

    // Optionally disable it as well (though hidden fields are already non-interactive)
    form.disableField('custom.positionOther');
}

