scriptTask.script:
logger.info("Creating User");

var content = execution.getVariables();
var requestId = content.get('id');
var failureReason = null;

try {
  var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
}
catch (e) {
  failureReason = "Creating User: Error reading request with id " + requestId;
}

if(!failureReason) {
  try {
    var payload = requestObj.request.user.object;

    /** Create new user **/
    var result = openidm.create('managed/alpha_user', null, payload, queryParams);
    logger.info("User created with userName " + result.userName + " and _id " + result._id + ".")

    /** Send new user email **/
    var body = { 
        subject: "Welcome " + payload.givenName + " " + payload.sn + "!",
        to: payload.mail,
        body: "Your new user has been created.\n\nUsername: " + payload.userName,
        object: {}
    };

    if(payload.manager && payload.manager._ref){
        logger.info("Getting manager information for " + payload.userName + " create user welcome email.")
        try {
            var managerResult = openidm.read(payload.manager._ref);
            body.cc = managerResult.mail;
          } catch (e) {
            logger.info("Unable to read manager information for " + payload.userName + " create user welcome email. " + e.message)
        }
    }
    openidm.action("external/email", "send", body);
  }
  catch (e) {
    failureReason = "Creating user failed: Error during creation of user " + payload.userName + ". Error message: " + e.message;
  }

  var decision = {'status': 'complete', 'decision': 'approved'};
  if (failureReason) {
    decision.outcome = 'not provisioned';
    decision.comment = failureReason;
    decision.failure = true;
  }
  else {
    decision.outcome = 'provisioned';
  }

  var queryParams = { '_action': 'update'};
  openidm.action('iga/governance/requests/' + requestId, 'POST', decision, queryParams);
  logger.info("Request " + requestId + " completed.");
}

logger.info("Create User - rejecting request");

var content = execution.getVariables();
var requestId = content.get('id');

var requestIndex = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
var decision = {'outcome': 'denied', 'status': 'complete', 'decision': 'rejected'};
var queryParams = { '_action': 'update'};
openidm.action('iga/governance/requests/' + requestId, 'POST', decision, queryParams);

// This permission check script will check that the requester has proper privileges to
// create a user.  If so, it will skip any approval process and directly move to create the new user.

logger.info("Create User - Permission check");
var content = execution.getVariables();
var requestId = content.get('id');
var skipApproval = false;

try {
    // Read the request object
    var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
    var requester = requestObj.requester

    if(requester.id.startsWith('managed/user/')){
        // If requester is a normal managed user, check that the user has permissions to create a user
        var userId = requester.id.split('/');
        var user = openidm.action('iga/governance/user', 'GET', {}, {'endUserId': userId[2], 'scopePermission': 'createUser', '_queryFilter': `id+eq+'` + userId[2] + `'`})
        if(user.result.length > 0){
            skipApproval = true;
        }
    }
    else{
      // Tenant admins and system requests
      skipApproval = true;
    }
}
catch (e) {
  logger.info("Request permission check failed: " + e.message);
}

execution.setVariable("skipApproval", skipApproval);

logger.info("Create User - marking request as auto approved.");

var content = execution.getVariables();
var requestId = content.get('id');
var queryParams = {
  "_action": "update"
}
try {
    var decision = {
        "decision": "approved",
        "comment": "Request auto-approved due to requester having create user privileges."
    }
    openidm.action('iga/governance/requests/' + requestId, 'POST', decision, queryParams);
}
catch (e) {
    var failureReason = "Failure updating decision on request. Error message: " + e.message;
    var update = {'comment': failureReason, 'failure': true};
    openidm.action('iga/governance/requests/' + requestId, 'POST', update, queryParams);
}

logger.info("Running application grant request validation");

var content = execution.getVariables();
var requestId = content.get('id');
var failureReason = null;
var applicationId = null;
var app = null;

try {
  var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
  applicationId = requestObj.application.id;
}
catch (e) {
  failureReason = "Validation failed: Error reading request with id " + requestId;
}

// Validation 1 - Check application exists
if (!failureReason) {
  try {
    app = openidm.read('managed/alpha_application/' + applicationId);
    if (!app) {
      failureReason = "Validation failed: Cannot find application with id " + applicationId;
    }
  }
  catch (e) {
    failureReason = "Validation failed: Error reading application with id " + applicationId + ". Error message: " + e.message;
  }
}

// Validation 2 - Check the user does not already have application granted
// Note: this is done at request submission time as well, the following is an example of how to check user's accounts
if (!failureReason) {
  try {
    var user = openidm.read('managed/alpha_user/' + requestObj.user.id, null, [ 'effectiveApplications' ]);
    user.effectiveApplications.forEach(effectiveApp => {
      if (effectiveApp._id === applicationId) {
        failureReason = "Validation failed: User with id " + requestObj.user.id + " already has effective application " + applicationId;
      }
    })
  }
  catch (e) {
    failureReason = "Validation failed: Unable to check effective applications of user with id " + requestObj.user.id + ". Error message: " + e.message;
  }
}

if (failureReason) {
  logger.info("Validation failed: " + failureReason);
}
execution.setVariable("failureReason", failureReason);

logger.info("Rejecting request");

var content = execution.getVariables();
var requestId = content.get('id');

// Complete request as rejected
var requestIndex = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
var decision = {'outcome': 'denied', 'status': 'complete', 'decision': 'rejected'};
var queryParams = { '_action': 'update'};
openidm.action('iga/governance/requests/' + requestId, 'POST', decision, queryParams);

logger.info("Provisioning");

var content = execution.getVariables();
var requestId = content.get('id');
var failureReason = null;

try {
  var requestObj = openidm.action('iga/governance/requests/' + requestId, 'GET', {}, {});
  logger.info("requestObj: " + requestObj);
}
catch (e) {
  failureReason = "Provisioning failed: Error reading request with id " + requestId;
}

if(!failureReason) {
  try {
    var request = requestObj.request;
    var payload = {
      "applicationId": request.common.applicationId,
      "auditContext": {},
      "grantType": "request",
      "requestId": requestObj.id,
    };
    var queryParams = {
      "_action": "add"
    }

    logger.info("Creating account: " + payload);
    var result = openidm.action('iga/governance/user/' + request.common.userId + '/applications' , 'POST', payload,queryParams);
  }
  catch (e) {
    var err = e.javaException; 
        err = JSON.parse(err.detail);
        var message = err && err.body ? err.body.response : e.message;
        failureReason = "Provisioning failed: Error provisioning account to user " + request.common.userId + " for application " + request.common.applicationId + ". Error message: " + message;
  }

  var decision = {'status': 'complete'};
  if (failureReason) {
    decision.outcome = 'not provisioned';
    decision.comment = failureReason;
