function generateUsername(givenName, surname) {
const usernamePrefix = (givenName[0] + surname[0]).toLowerCase();
const data = openidm.query("managed/alpha_user", {'_queryFilter': `userName sw "${usernamePrefix}"`}, ["userName"]);
